-- ============================================================
-- BACKFILL: recompute Orders.TotalAmount from its line items.
-- Absolute SET (not +=) so re-running this file never double-counts.
-- ============================================================
UPDATE Orders o
SET o.TotalAmount = (
    SELECT COALESCE(SUM(oi.Subtotal), 0)
    FROM OrderItems oi
    WHERE oi.OrderID = o.OrderID
);
